CREATE OR REPLACE FUNCTION fpa_fin_account_id_rule (as_acc_id char,as_vh_no char,ai_seqno integer) RETURNS varchar AS $body$
DECLARE

  ls_account_id sc_fin_vourcher_detail.account_id%type;

BEGIN
  begin
    select  account_id into STRICT ls_account_id
    from    sc_fin_vourcher_detail
    where (vourcher_no = as_vh_no)
    and (seq_no = ai_seqno);
  end;
END;
